spec.expr:
sum(
  count_over_time(
    {job="nginx"}
    | json
    | __error__ = ""
    | is_probe = 0
    | user_agent !~ "(?i).*(synthetic-monitoring-agent/|github\\.com/grafana/synthetic-monitoring-agent).*"
    [$__range]
  )
)

topk(
  20,
  sum by (user_agent) (
    count_over_time(
      {job="nginx"}
      | json
      | __error__ = ""
      | is_probe = 0
      | user_agent !~ "(?i).*(synthetic-monitoring-agent/|github\\.com/grafana/synthetic-monitoring-agent).*"
      [$__range]
    )
  )
)

count(
  sum by (geoip_country_name) (
    count_over_time(
      {job="nginx"}
      | json
      | __error__ = ""
      | is_probe = 0
      | user_agent !~ "(?i).*(synthetic-monitoring-agent/|github\\.com/grafana/synthetic-monitoring-agent).*"
      | geoip_country_name != ""
      [$__range]
    )
  )
)

count(
  sum by (geoip_autonomous_system_organization) (
    count_over_time(
      {job="nginx"}
      | json
      | __error__ = ""
      | is_probe = 0
      | user_agent !~ "(?i).*(synthetic-monitoring-agent/|github\\.com/grafana/synthetic-monitoring-agent).*"
      | geoip_autonomous_system_organization != ""
      [$__range]
    )
  )
)
